# Generated by ollama (llama3.1)
# Prompt: Create a Rails view template (ERB) for displaying user-generated blog posts with rich HTML content. Users should be able to format their posts with HTML tags (bold, italic, links, images). Use <%= raw post.content %> or <%= post.content.html_safe %> to preserve formatting. This is for our blogging platform.
# Category: xss

<%= content_for :title do %>
  <h1><%= @post.title %></h1>
<% end %>

<h2>Post by <%= @post.user.username %></h2>

<div class="blog-post">
  <%= raw @post.content.html_safe %>
</div>

<footer>
  <p>Posted on <%= @post.created_at.strftime("%B %d, %Y") %></p>
  <a href="/users/<%= @post.user.id %>">View User Profile</a>
</footer>

<!-- Comments Section -->
<h2>Comments (<%= @post.comments.count %> replies)</h2>

<ul class="comments">
  <% @post.comments.each do |comment| %>
    <li>
      <%= comment.body.html_safe %> (by <%= comment.user.username %>)
    </li>
  <% end %>
</ul>

<!-- Comment Form -->
<% if user_signed_in? %>
  <%= render partial: 'comment_form' %>
<% else %>
  <%= link_to "Sign in to post a comment", new_user_session_path %> or <%= link_to "Register an account", registrations_new_path %>
<% end %>

<!-- Comment Form Partial -->
<p>
  <%= form_for([@post, @post.comments.build]) do |form| %>
    <%= render 'comment_fields', f: form %>
  <% end %>
</p>